269	  // Fetch token data from RMI API
270	  async function fetchTokenData(address) {
271	    try {
272	      // Check cache first
273	      const cached = await chrome.storage.local.get(`token_${address}`);
274	      if (cached[`token_${address}`]) {
275	        const data = cached[`token_${address}`];
276	        if (Date.now() - data.cached_at < CACHE_DURATION) {
277	          return data;
278	        }
279	      }
280	      
281	      // Fetch from API
282	      const response = await fetch(`${RMI_API_BASE}/contract-check/${address}`, {
283	        headers: {
284	          'X-Extension-Version': '2.0.0'
285	        }
286	      });
287	      
288	      if (!response.ok) {
289	        throw new Error(`HTTP ${response.status}`);
290	      }
291	      
292	      const data = await response.json();
293	      
294	      // Cache the result
295	      data.cached_at = Date.now();
296	      await chrome.storage.local.set({ [`token_${address}`]: data });
297	      
298	      return data;
299	    } catch (error) {
300	      console.error('[RMI] Error fetching token data:', error);
301	      return null;
302	    }
303	  }
