{"path": "rmi/infrastructure/extension/content_scripts/universal-detector.js", "content": "/**
 * RMI Universal Chart Detector
 * Detects crypto tokens on any charting website and shows mini analysis blip
 * Works on TradingView, CoinGecko, CoinMarketCap, and any site with chart data
 */

(function() {
  'use strict';

  const RMI_API_BASE = 'https://intel.cryptorugmunch.com/api';
  const CACHE_DURATION = 5 * 60 * 1000; // 5 minutes

  // Site configurations for token extraction
  const SITE_CONFIGS = {
    'tradingview.com': {
      name: 'TradingView',
      extractToken: () => {
        // Try multiple selectors for TV
        const symbolEl = document.querySelector('[data-name="legend-series-item"] .titleWrapper-qJiKkVIX');
        const headerSymbol = document.querySelector('.symbol-SYMW4qEV');
        const chartSymbol = document.querySelector('[data-symbol]');

        let symbol = null;
        if (symbolEl) symbol = symbolEl.textContent.trim();
        else if (headerSymbol) symbol = headerSymbol.textContent.trim();
        else if (chartSymbol) symbol = chartSymbol.getAttribute('data-symbol');

        // Check if it's a crypto pair
        if (symbol && (symbol.includes('USDT') || symbol.includes('USD') || symbol.includes('BTC') || symbol.includes('ETH'))) {
          // Extract base token (e.g., BTC from BTCUSDT)
          const baseToken = symbol.replace(/USDT|USD|BUSD|USDC/g, '').replace(/PERP|-/g, '');
          return { symbol: baseToken, pair: symbol, exchange: 'tradingview' };
        }
        return null;
      }
    },
    'coingecko.com': {
      name: 'CoinGecko',
      extractToken: () => {
        // Try to get from URL first
        const urlMatch = location.pathname.match(/\/en\/coins\/([^\/]+)/);
        if (urlMatch) {
          const coinName = urlMatch[1];
          // Get symbol from page
          const symbolEl = document.querySelector('.coin-symbol, [data-coin-symbol], .tw-text-gray-500.tw-text-sm');
          const symbol = symbolEl ? symbolEl.textContent.replace(/[()]/g, '').toUpperCase() : coinName.toUpperCase();
          return { symbol, id: coinName, exchange: 'coingecko' };
        }

        // From coin links in tables
        const coinLinks = document.querySelectorAll('a[href*="/coins/"]');
        const tokens = [];
        coinLinks.forEach(link => {
          const match = link.href.match(/\/coins\/([^\/]+)/);
          if (match) {
            const symbolEl = link.querySelector('.coin-symbol, .token-symbol') || link;
            const symbol = symbolEl.textContent.match(/\(([A-Z0-9]+)\)/)?.[1] || match[1].toUpperCase();
            tokens.push({ symbol, id: match[1], exchange: 'coingecko' });
          }
        });
        return tokens.length > 0 ? tokens : null;
      }
    },
    'coinmarketcap.com': {
      name: 'CoinMarketCap',
      extractToken: () => {
        // From URL
        const urlMatch = location.pathname.match(/\/currencies\/([^\/]+)/);
        if (urlMatch) {
          const symbolEl = document.querySelector('.nameSymbol, [data-symbol], .coin-symbol');
          const priceEl = document.querySelector('.priceValue');
          const symbol = symbolEl ? symbolEl.textContent.trim().toUpperCase() : urlMatch[1].toUpperCase();
          return { symbol, id: urlMatch[1], exchange: 'coinmarketcap', hasPrice: !!priceEl };
        }

        // From tables
        const rows = document.querySelectorAll('table tbody tr');
        const tokens = [];
        rows.forEach(row => {
          const symbolEl = row.querySelector('.symbol, .coin-symbol, [data-symbol]');
          const link = row.querySelector('a[href*="/currencies/"]');
          if (link) {
            const match = link.href.match(/\/currencies\/([^\/]+)/);
            if (match) {
              const symbol = symbolEl ? symbolEl.textContent.trim().toUpperCase() : match[1].toUpperCase();
              tokens.push({ symbol, id: match[1], exchange: 'coinmarketcap' });
            }
          }
        });
        return tokens.length > 0 ? tokens : null;
      }
    }
  };

  // State
  let detectedTokens = new Map();
  let currentSite = null;
  let observer = null;
  let blipContainer = null;

  // Initialize
  function init() {
    const hostname = location.hostname.replace('www.', '');

    // Find matching site config
    for (const [domain, config] of Object.entries(SITE_CONFIGS)) {
      if (hostname.includes(domain)) {
        currentSite = { domain, ...config };
        break;
      }
    }

    // Even if no specific config, try generic detection
    if (!currentSite) {
      currentSite = { name: 'Generic', domain: hostname, extractToken: genericTokenExtractor };
    }

    // Check consent before starting
    checkConsent().then(hasConsent => {
      if (hasConsent) {
        startDetection();
      }
    });

    // Listen for messages from popup/background
    chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
      if (message.action === 'scanCurrentToken') {
        const token = currentSite.extractToken();
        sendResponse({ token, site: currentSite.name });
      }
      return true;
    });
  }

  // Generic token extractor for unknown sites
  function genericTokenExtractor() {
    const tokens = [];
    const seen = new Set();

    // Look for common patterns
    const patterns = [
      // Solana addresses (base58, 32-44 chars)
      { regex: /[1-9A-HJ-NP-Za-km-z]{32,44}/g, chain: 'solana' },
      // Ethereum addresses (0x + 40 hex)
      { regex: /0x[a-fA-F0-9]{40}/g, chain: 'ethereum' },
      // Token symbols in parentheses on chart pages
      { regex: /\(([A-Z]{2,10})\)/g, type: 'symbol' }
    ];

    // Scan page text for patterns
    const pageText = document.body.innerText;

    patterns.forEach(pattern => {
      const matches = pageText.matchAll(pattern.regex);
      for (const match of matches) {
        const value = match[0];
        if (seen.has(value)) continue;
        seen.add(value);

        if (pattern.type === 'symbol') {
          tokens.push({ symbol: match[1], exchange: 'generic' });
        } else {
          tokens.push({ address: value, chain: pattern.chain, exchange: 'generic' });
        }
      }
    });

    return tokens.length > 0 ? tokens : null;
  }

  // Check user consent
  async function checkConsent() {
    const result = await chrome.storage.local.get(['rmi_consent', 'subscription']);
    return result.rmi_consent === true;
  }

  // Start detection loop
  function startDetection() {
    // Initial scan
    scanForTokens();

    // Watch for DOM changes (SPA navigation)
    observer = new MutationObserver(debounce(() => {
      scanForTokens();
    }, 500));

    observer.observe(document.body, { childList: true, subtree: true });

    // Periodic scan for dynamic content
    setInterval(scanForTokens, 3000);
  }

  // Scan page for tokens
  async function scanForTokens() {
    const tokens = currentSite.extractToken();
    if (!tokens) return;

    const tokenArray = Array.isArray(tokens) ? tokens : [tokens];

    for (const token of tokenArray) {
      const key = token.address || token.symbol || token.id;
      if (!key) continue;

      // Skip if already processed recently
      if (detectedTokens.has(key)) {
        const cached = detectedTokens.get(key);
        if (Date.now() - cached.timestamp < CACHE_DURATION) {
          continue;
        }
      }

      // Fetch analysis
      const analysis = await fetchTokenAnalysis(token);
      if (analysis) {
        detectedTokens.set(key, { token, analysis, timestamp: Date.now() });
        showCornerBlip(token, analysis);
      }
    }
  }

  // Fetch token analysis from API
  async function fetchTokenAnalysis(token) {
    try {
      // Check subscription tier
      const { subscription } = await chrome.storage.local.get(['subscription']);
      const tier = subscription?.tier || 'free';

      let endpoint;
      if (token.address) {
        endpoint = `${RMI_API_BASE}/v3/token/${token.chain}/${token.address}?tier=${tier}`;
      } else if (token.symbol) {
        endpoint = `${RMI_API_BASE}/v3/token/symbol/${token.symbol}?tier=${tier}`;
      } else {
        return null;
      }

      const response = await fetch(endpoint, {
        headers: {
          'X-Extension-Version': '3.0.0',
          'X-Site': currentSite.name
        }
      });

      if (!response.ok) {
        // Use cached data if available
        const cached = await chrome.storage.local.get(`analysis_${token.address || token.symbol}`);
        return cached[`analysis_${token.address || token.symbol}`] || null;
      }

      const data = await response.json();

      // Cache result
      await chrome.storage.local.set({
        [`analysis_${token.address || token.symbol}`]: { ...data, cached_at: Date.now() }
      });

      return data;
    } catch (error) {
      console.error('[RMI] Analysis fetch error:', error);
      return null;
    }
  }

  // Show corner blip with analysis
  function showCornerBlip(token, analysis) {
    // Remove existing blip for this token
    const existing = document.getElementById(`rmi-blip-${token.symbol || token.address}`);
    if (existing) existing.remove();

    if (!blipContainer) {
      blipContainer = createBlipContainer();
    }

    const blip = document.createElement('div');
    blip.id = `rmi-blip-${token.symbol || token.address}`;
    blip.className = 'rmi-corner-blip';
    blip.innerHTML = `
      <div class="rmi-blip-header">
        <span class="rmi-blip-symbol">${token.symbol || 'Unknown'}</span>
        <span class="rmi-blip-score rmi-score-${analysis.risk_level}">${analysis.overall_score}/100</span>
      </div>
      <div class="rmi-blip-fundamentals">
        ${generateFundamentalsHTML(analysis, token)}
      </div>
      <div class="rmi-blip-actions">
        <button class="rmi-blip-btn rmi-blip-btn-primary" data-action="details">
          ${analysis.is_premium ? 'Full Report' : 'Upgrade for More'}
        </button>
        <button class="rmi-blip-btn" data-action="dismiss">×</button>
      </div>
    `;

    // Add event listeners
    blip.querySelector('[data-action="details"]').addEventListener('click', () => {
      showDetailsModal(token, analysis);
    });

    blip.querySelector('[data-action="dismiss"]').addEventListener('click', () => {
      blip.remove();
    });

    blipContainer.appendChild(blip);

    // Auto-remove after 30 seconds if not interacted
    setTimeout(() => {
      if (blip.parentNode) {
        blip.classList.add('rmi-blip-fade-out');
        setTimeout(() => blip.remove(), 500);
      }
    }, 30000);
  }

  // Create floating blip container
  function createBlipContainer() {
    const container = document.createElement('div');
    container.id = 'rmi-blip-container';
    container.innerHTML = `
      <style>
        #rmi-blip-container {
          position: fixed;
          bottom: 20px;
          right: 20px;
          z-index: 999999;
          display: flex;
          flex-direction: column;
          gap: 10px;
          max-width: 280px;
          font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
        }
      </style>
    `;
    document.body.appendChild(container);
    return container;
  }

  // Generate fundamentals HTML based on tier
  function generateFundamentalsHTML(analysis, token) {
    const { subscription } = { subscription: { tier: 'free' } }; // Default to free
    const isPremium = subscription?.tier === 'premium';

