(function() {
  'use strict';

  const RMI_API_BASE = 'https://intel.cryptorugmunch.com/api';
  const CACHE_DURATION = 5 * 60 * 1000;

  const SITE_CONFIGS = {
    'tradingview.com': {
      name: 'TradingView',
      extractToken: () => {
        const symbolEl = document.querySelector('[data-name="legend-series-item"] .titleWrapper-qJiKkVIX');
        const headerSymbol = document.querySelector('.symbol-SYMW4qEV');
        const chartSymbol = document.querySelector('[data-symbol]');

        let symbol = null;
        if (symbolEl) symbol = symbolEl.textContent.trim();
        else if (headerSymbol) symbol = headerSymbol.textContent.trim();
        else if (chartSymbol) symbol = chartSymbol.getAttribute('data-symbol');

        if (symbol && (symbol.includes('USDT') || symbol.includes('USD') || symbol.includes('BTC'))) {
          const baseToken = symbol.replace(/USDT|USD|BUSD|USDC/g, '').replace(/PERP|-/g, '');
          return { symbol: baseToken, pair: symbol, exchange: 'tradingview' };
        }
        return null;
      }
    },
    'coingecko.com': {
      name: 'CoinGecko',
      extractToken: () => {
        const urlMatch = location.pathname.match(/\/en\/coins\/([^\/]+)/);
        if (urlMatch) {
          const symbolEl = document.querySelector('.coin-symbol, [data-coin-symbol]');
          const symbol = symbolEl ? symbolEl.textContent.replace(/[()]/g, '').toUpperCase() : urlMatch[1].toUpperCase();
          return { symbol, id: urlMatch[1], exchange: 'coingecko' };
        }
        return null;
      }
    },
    'coinmarketcap.com': {
      name: 'CoinMarketCap',
      extractToken: () => {
        const urlMatch = location.pathname.match(/\/currencies\/([^\/]+)/);
        if (urlMatch) {
          const symbolEl = document.querySelector('.nameSymbol, [data-symbol]');
          const symbol = symbolEl ? symbolEl.textContent.trim().toUpperCase() : urlMatch[1].toUpperCase();
          return { symbol, id: urlMatch[1], exchange: 'coinmarketcap' };
        }
        return null;
      }
    }
  };

  let detectedTokens = new Map();
  let currentSite = null;
  let observer = null;

  function init() {
    const hostname = location.hostname.replace('www.', '');

    for (const [domain, config] of Object.entries(SITE_CONFIGS)) {
      if (hostname.includes(domain)) {
        currentSite = { domain, ...config };
        break;
      }
    }

    if (!currentSite) {
      currentSite = { name: 'Generic', domain: hostname, extractToken: genericTokenExtractor };
    }

    checkConsent().then(hasConsent => {
      if (hasConsent) startDetection();
    });
  }

  function genericTokenExtractor() {
    const tokens = [];
    const seen = new Set();
    const pageText = document.body.innerText;

    const patterns = [
      { regex: /[1-9A-HJ-NP-Za-km-z]{32,44}/g, chain: 'solana' },
      { regex: /0x[a-fA-F0-9]{40}/g, chain: 'ethereum' },
      { regex: /\(([A-Z]{2,10})\)/g, type: 'symbol' }
    ];

    patterns.forEach(pattern => {
      const matches = pageText.matchAll(pattern.regex);
      for (const match of matches) {
        const value = match[0];
        if (seen.has(value)) continue;
        seen.add(value);

        if (pattern.type === 'symbol') {
          tokens.push({ symbol: match[1], exchange: 'generic' });
        } else {
          tokens.push({ address: value, chain: pattern.chain, exchange: 'generic' });
        }
      }
    });

    return tokens.length > 0 ? tokens : null;
  }

  async function checkConsent() {
    const result = await chrome.storage.local.get(['rmi_consent']);
    return result.rmi_consent === true;
  }

  function startDetection() {
    scanForTokens();
    observer = new MutationObserver(debounce(() => scanForTokens(), 500));
    observer.observe(document.body, { childList: true, subtree: true });
    setInterval(scanForTokens, 3000);
  }

  async function scanForTokens() {
    const tokens = currentSite.extractToken();
    if (!tokens) return;

    const tokenArray = Array.isArray(tokens) ? tokens : [tokens];

    for (const token of tokenArray) {
      const key = token.address || token.symbol || token.id;
      if (!key) continue;

      if (detectedTokens.has(key)) {
        const cached = detectedTokens.get(key);
        if (Date.now() - cached.timestamp < CACHE_DURATION) continue;
      }

      const analysis = await fetchTokenAnalysis(token);
      if (analysis) {
        detectedTokens.set(key, { token, analysis, timestamp: Date.now() });
        showCornerBlip(token, analysis);
      }
    }
  }

  async function fetchTokenAnalysis(token) {
    try {
      const { subscription } = await chrome.storage.local.get(['subscription']);
      const tier = subscription?.tier || 'free';

      let endpoint;
      if (token.address) {
        endpoint = `${RMI_API_BASE}/v3/token/${token.chain}/${token.address}?tier=${tier}`;
      } else if (token.symbol) {
        endpoint = `${RMI_API_BASE}/v3/token/symbol/${token.symbol}?tier=${tier}`;
      } else return null;

      const response = await fetch(endpoint, {
        headers: { 'X-Extension-Version': '3.0.0', 'X-Site': currentSite.name }
      });

      if (!response.ok) {
        const cached = await chrome.storage.local.get(`analysis_${token.address || token.symbol}`);
        return cached[`analysis_${token.address || token.symbol}`] || null;
      }

      const data = await response.json();
      await chrome.storage.local.set({
        [`analysis_${token.address || token.symbol}`]: { ...data, cached_at: Date.now() }
      });

      return data;
    } catch (error) {
      return null;
    }
  }

