    if (price < 0.000001) return price.toExponential(2);
    if (price < 0.01) return price.toFixed(6);
    if (price < 1) return price.toFixed(4);
    return price.toFixed(2);
  }

  function formatCompact(num) {
    if (!num) return '0';
    if (num >= 1e9) return (num / 1e9).toFixed(2) + 'B';
    if (num >= 1e6) return (num / 1e6).toFixed(2) + 'M';
    if (num >= 1e3) return (num / 1e3).toFixed(2) + 'K';
    return num.toString();
  }

  // Initialize
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
"}

{"path": "rmi/infrastructure/extension/content_scripts/tradingview.js", "content": "/**
 * RMI TradingView Integration
 * Enhanced detection and display for TradingView charts
 */

(function() {
  'use strict';

  const RMI_API_BASE = 'https://intel.cryptorugmunch.com/api';
  let currentSymbol = null;
  let analysisCache = null;

  function init() {
    console.log('[RMI] TradingView integration loaded');

    // Wait for chart to load
    waitForChart().then(() => {
      startMonitoring();
    });
  }

  async function waitForChart() {
    return new Promise(resolve => {
      const check = () => {
        const chart = document.querySelector('#chart-container') || 
                      document.querySelector('.chart-container') ||
                      document.querySelector('[data-name="chart-container"]');
        if (chart) {
          resolve(chart);
        } else {
          setTimeout(check, 500);
        }
      };
      check();
    });
  }

  function startMonitoring() {
    // Check for symbol changes
    setInterval(() => {
      const symbol = extractSymbol();
      if (symbol && symbol !== currentSymbol) {
        currentSymbol = symbol;
        onSymbolChange(symbol);
      }
    }, 1000);

    // Inject floating button
    injectFloatingButton();
  }

  function extractSymbol() {
    // Multiple strategies to get the symbol
    const strategies = [
      () => {
        const title = document.querySelector('.titleWrapper-qJiKkVIX');
        return title ? title.textContent.trim() : null;
      },
      () => {
        const header = document.querySelector('.symbol-SYMW4qEV');
        return header ? header.textContent.trim() : null;
      },
      () => {
        const chart = document.querySelector('[data-symbol]');
        return chart ? chart.getAttribute('data-symbol') : null;
      },
      () => {
        // From URL hash
        const hash = location.hash;
        const match = hash.match(/symbol=([^&]+)/);
        return match ? decodeURIComponent(match[1]) : null;
      }
    ];

    for (const strategy of strategies) {
      const result = strategy();
      if (result) return result;
    }
    return null;
  }

  function onSymbolChange(symbol) {
    console.log('[RMI] Symbol changed:', symbol);

    // Check if it's a crypto symbol
    if (!isCryptoSymbol(symbol)) return;

    const baseToken = extractBaseToken(symbol);
    fetchAnalysis(baseToken, symbol);
  }

  function isCryptoSymbol(symbol) {
    const cryptoIndicators = ['USDT', 'USD', 'BTC', 'ETH', 'PERP', 'BUSD', 'USDC'];
    return cryptoIndicators.some(ind => symbol.includes(ind));
  }

  function extractBaseToken(symbol) {
    // Extract base from pairs like BTCUSDT, ETHUSD, etc.
    return symbol.replace(/USDT|USD|BUSD|USDC|PERP/g, '').replace(/-/g, '');
  }

  async function fetchAnalysis(token, fullSymbol) {
    try {
      const { subscription } = await chrome.storage.local.get(['subscription']);
      const tier = subscription?.tier || 'free';

      const response = await fetch(
        `${RMI_API_BASE}/v3/token/symbol/${token}?tier=${tier}&source=tradingview`,
        { headers: { 'X-Extension-Version': '3.0.0' } }
      );

      if (!response.ok) throw new Error('API error');

      const data = await response.json();
      analysisCache = data;

      // Update UI
      updateFloatingButton(data);

      // Show corner blip
      showTradingViewBlip(token, fullSymbol, data);

    } catch (error) {
      console.error('[RMI] Analysis error:', error);
    }
  }

  function injectFloatingButton() {
    if (document.getElementById('rmi-tv-button')) return;

    const button = document.createElement('div');
    button.id = 'rmi-tv-button';
    button.className = 'rmi-tv-floating-btn';
    button.innerHTML = `
      <div class="rmi-tv-btn-content">
        <span class="rmi-tv-icon">🛡️</span>
        <span class="rmi-tv-text">RMI</span>
        <span class="rmi-tv-score">--</span>
      </div>
    `;

    button.addEventListener('click', () => {
      if (analysisCache) {
        showAnalysisPanel(analysisCache);
      } else {
        showConnectPrompt();
      }
    });

    document.body.appendChild(button);
  }

  function updateFloatingButton(data) {
    const button = document.getElementById('rmi-tv-button');
    if (!button) return;

    const scoreEl = button.querySelector('.rmi-tv-score');
    scoreEl.textContent = `${data.overall_score}/100`;
    scoreEl.className = `rmi-tv-score rmi-score-${data.risk_level}`;
  }

  function showTradingViewBlip(token, symbol, analysis) {
    // Remove existing
    const existing = document.getElementById('rmi-tv-blip');
    if (existing) existing.remove();

    const blip = document.createElement('div');
    blip.id = 'rmi-tv-blip';
    blip.className = 'rmi-tv-blip';
    blip.innerHTML = `
      <div class="rmi-tv-blip-header">
        <span class="rmi-tv-blip-symbol">${token}</span>
        <span class="rmi-tv-blip-score rmi-score-${analysis.risk_level}">${analysis.overall_score}/100</span>
      </div>
      <div class="rmi-tv-blip-body">
        <div class="rmi-tv-metric">
          <span>Risk</span>
          <span class="rmi-risk-${analysis.risk_level}">${analysis.risk_level}</span>
        </div>
        ${analysis.price ? `
          <div class="rmi-tv-metric">
            <span>Price</span>
            <span>$${formatPrice(analysis.price)}</span>
          </div>
        ` : ''}
      </div>
      <div class="rmi-tv-blip-footer">
        <button class="rmi-tv-blip-btn" data-action="details">Details</button>
        <button class="rmi-tv-blip-btn rmi-tv-blip-btn-upgrade" data-action="upgrade">Upgrade $5/mo</button>
      </div>
    `;

    blip.querySelector('[data-action="details"]').addEventListener('click', () => {
      showAnalysisPanel(analysis);
    });

    blip.querySelector('[data-action="upgrade"]').addEventListener('click', () => {
      showUpgradeModal();
    });

    document.body.appendChild(blip);

    // Auto-hide after 20s
    setTimeout(() => {
      blip.classList.add('rmi-tv-blip-fade');
      setTimeout(() => blip.remove(), 500);
    }, 20000);
  }

  function showAnalysisPanel(analysis) {
    const existing = document.getElementById('rmi-tv-panel');
    if (existing) {
      existing.remove();
      return;
    }

    const panel = document.createElement('div');
    panel.id = 'rmi-tv-panel';
    panel.className = 'rmi-tv-panel';
    panel.innerHTML = `
      <div class="rmi-tv-panel-header">
        <h3>RMI Analysis</h3>
        <button class="rmi-tv-panel-close">&times;</button>
      </div>
      <div class="rmi-tv-panel-body">
        <div class="rmi-tv-score-large rmi-score-${analysis.risk_level}">
          ${analysis.overall_score}<span>/100</span>
        </div>
        <p class="rmi-tv-risk-label">${analysis.risk_level.toUpperCase()} RISK</p>

        <div class="rmi-tv-sections">
          <div class="rmi-tv-section">
            <h4>Quick Stats</h4>
            <div class="rmi-tv-stats">
              ${analysis.price ? `<div><span>Price</span><strong>$${formatPrice(analysis.price)}</strong></div>` : ''}
              ${analysis.volume_24h ? `<div><span>24h Vol</span><strong>$${formatCompact(analysis.volume_24h)}</strong></div>` : ''}
            </div>
          </div>

          <div class="rmi-tv-section rmi-tv-section-locked">
            <h4>🔒 Full Analysis</h4>
            <p>Upgrade to Pro for detailed fundamentals, risk breakdown, and smart alerts</p>
            <button class="rmi-tv-btn-upgrade" data-action="upgrade">Upgrade $5/month</button>
          </div>
        </div>

        ${(analysis.flags?.red || []).length > 0 ? `
          <div class="rmi-tv-flags">
            <h4>🚩 ${analysis.flags.red.length} Red Flags</h4>
            <p>Upgrade to see full details</p>
          </div>
        ` : ''}
      </div>
      <div class="rmi-tv-panel-footer">
        <a href="https://intel.cryptorugmunch.com/scan/${analysis.token_address || analysis.symbol}" 
           target="_blank" class="rmi-tv-link">Open Full Dashboard →</a>
      </div>
    `;

    panel.querySelector('.rmi-tv-panel-close').addEventListener('click', () => panel.remove());
    panel.querySelector('[data-action="upgrade"]')?.addEventListener('click', showUpgradeModal);

    document.body.appendChild(panel);
  }

  function showConnectPrompt() {
    const panel = document.createElement('div');
    panel.id = 'rmi-tv-panel';
    panel.className = 'rmi-tv-panel';
    panel.innerHTML = `
      <div class="rmi-tv-panel-header">
        <h3>RMI Analysis</h3>
        <button class="rmi-tv-panel-close">&times;</button>
      </div>
      <div class="rmi-tv-panel-body">
        <p>Waiting for chart data...</p>
        <p class="rmi-tv-hint">Navigate to a crypto pair to see analysis</p>
      </div>
    `;

    panel.querySelector('.rmi-tv-panel-close').addEventListener('click', () => panel.remove());
    document.body.appendChild(panel);
  }

  function showUpgradeModal() {
    const modal = document.createElement('div');
    modal.className = 'rmi-tv-modal-overlay';
    modal.innerHTML = `
      <div class="rmi-tv-upgrade-modal">
        <h3>Upgrade to RMI Pro</h3>
        <div class="rmi-tv-price">
          <span class="rmi-tv-price-amount">$5</span>
          <span class="rmi-tv-price-period">/month</span>
        </div>
        <ul class="rmi-tv-features">
          <li>Full fundamentals on every chart</li>
          <li>Detailed risk breakdown</li>
          <li>Smart alerts</li>
          <li>Works on all major platforms</li>
        </ul>
        <button class="rmi-tv-btn-primary" data-action="subscribe">Start Free Trial</button>
        <p class="rmi-tv-trial">7 days free, cancel anytime</p>
        <button class="rmi-tv-modal-close">&times;</button>
      </div>
    `;

    modal.querySelector('[data-action="subscribe"]').addEventListener('click', () => {
      chrome.tabs.create({ url: 'https://intel.cryptorugmunch.com/checkout?plan=pro-extension&source=tradingview' });
      modal.remove();
    });

    modal.querySelector('.rmi-tv-modal-close').addEventListener('click', () => modal.remove());
    modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });

    document.body.appendChild(modal);
  }

  // Utilities
  function formatPrice(price) {
    if (price < 0.000001) return price.toExponential(2);
    if (price < 0.01) return price.toFixed(6);
    if (price < 1) return price.toFixed(4);
    return price.toFixed(2);
  }

  function formatCompact(num) {
    if (!num) return '0';
    if (num >= 1e9) return (num / 1e9).toFixed(2) + 'B';
    if (num >= 1e6) return (num / 1e6).toFixed(2) + 'M';
    if (num >= 1e3) return (num / 1e3).toFixed(2) + 'K';
    return num.toString();
  }

  // Init
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
"}

{"path": "rmi/infrastructure/extension/content_scripts/rmi-overlay.css", "content": "/**
 * RMI Extension - Overlay Styles v3.0
 * Corner blips, modals, and TradingView-specific styles
 */

/* ===== Corner Blip Container ===== */
#rmi-blip-container {
  position: fixed;
  bottom: 20px;
  right: 20px;
  z-index: 999999;
  display: flex;
  flex-direction: column;
  gap: 10px;
  max-width: 280px;
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
}

/* ===== Corner Blip ===== */
.rmi-corner-blip {
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
  border: 1px solid #00d4ff;
  border-radius: 12px;
  padding: 12px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
  animation: rmi-blip-in 0.3s ease-out;
  min-width: 220px;
  max-width: 280px;
}

@keyframes rmi-blip-in {
  from { opacity: 0; transform: translateX(100px) scale(0.9); }
  to { opacity: 1; transform: translateX(0) scale(1); }
}

.rmi-blip-fade-out {
  animation: rmi-blip-out 0.5s ease-out forwards;
}

@keyframes rmi-blip-out {
  to { opacity: 0; transform: translateX(100px); }
}

.rmi-blip-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
  padding-bottom: 8px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.rmi-blip-symbol {
  font-size: 16px;
  font-weight: 700;
  color: #fff;
}

.rmi-blip-score {
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  font-weight: 700;
  padding: 4px 8px;
  border-radius: 6px;
}

.rmi-blip-metrics {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
  margin-bottom: 10px;
}

.rmi-metric {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.rmi-metric span:first-child {
  font-size: 10px;
  color: #94a3b8;
  text-transform: uppercase;
}

.rmi-metric span:last-child {
  font-size: 12px;
  font-weight: 600;
  color: #fff;
}

.rmi-metric-locked span:last-child {
  color: #64748b;
}

.rmi-locked {
  font-size: 10px !important;
  opacity: 0.7;
}

.rmi-blip-flags {
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 6px;
  padding: 6px 10px;
  margin-bottom: 10px;
}

.rmi-flag-count {
  font-size: 11px;
  color: #ef4444;
  font-weight: 500;
}

.rmi-blip-actions {
  display: flex;
  gap: 8px;
}

.rmi-blip-btn {
  flex: 1;
  padding: 8px 12px;
  border: none;
  border-radius: 6px;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.2s;
}

.rmi-blip-btn-primary {
  background: linear-gradient(90deg, #00d4ff, #0099cc);
  color: #000;
}

.rmi-blip-btn-primary:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(0, 212, 255, 0.3);
}

.rmi-blip-btn-dismiss {
  flex: 0 0 32px;
  background: rgba(255, 255, 255, 0.1);
  color: #94a3b8;
  font-size: 14px;
}

.rmi-blip-btn-dismiss:hover {
  background: rgba(239, 68, 68, 0.3);
  color: #ef4444;
}

/* ===== Modal Overlay ===== */
.rmi-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.8);
  backdrop-filter: blur(4px);
  z-index: 999999;
  display: flex;
  align-items: center;
  justify-content: center;
}

.rmi-modal {
  width: 90%;
  max-width: 420px;
  max-height: 80vh;
  background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
  border: 1px solid #00d4ff;
  border-radius: 16px;
  overflow: hidden;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
  animation: rmi-modal-in 0.3s ease-out;
}

@keyframes rmi-modal-in {
  from { opacity: 0; transform: scale(0.9) translateY(20px); }
  to { opacity: 1; transform: scale(1) translateY(0); }
}

.rmi-modal-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px 20px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.rmi-modal-title {
