}

.rmi-upgrade-hint {
  font-size: 11px;
  color: #00d4ff;
  font-weight: 500;
}

.rmi-basic-flags {
  background: rgba(239, 68, 68, 0.1);
  border: 1px solid rgba(239, 68, 68, 0.3);
  border-radius: 10px;
  padding: 14px;
