}

/* ===== Risk Score Colors ===== */
.rmi-score-critical, .rmi-risk-critical { background: #ef4444; color: #fff; }
.rmi-score-high, .rmi-risk-high { background: #f97316; color: #fff; }
.rmi-score-medium, .rmi-risk-medium { background: #eab308; color: #000; }
.rmi-score-low, .rmi-risk-low { background: #22c55e; color: #fff; }
.rmi-score-safe, .rmi-risk-safe { background: #10b981; color: #fff; }
.rmi-score-unknown, .rmi-risk-unknown { background: #6b7280; color: #fff; }

/* ===== TradingView Specific ===== */
.rmi-tv-floating-btn {
  position: fixed;
  top: 100px;
  right: 20px;
  z-index: 99999;
  background: linear-gradient(135deg, #1a1a2e, #16213e);
  border: 1px solid #00d4ff;
  border-radius: 10px;
  padding: 8px 12px;
  cursor: pointer;
  box-shadow: 0 4px 20px rgba(0, 0, 0, 0.4);
  transition: all 0.2s;
}

.rmi-tv-floating-btn:hover {
  transform: scale(1.05);
  box-shadow: 0 6px 30px rgba(0, 212, 255, 0.3);
}

.rmi-tv-btn-content {
  display: flex;
  align-items: center;
  gap: 6px;
}

.rmi-tv-icon {
  font-size: 16px;
}

.rmi-tv-text {
  font-size: 12px;
  font-weight: 600;
  color: #fff;
}

.rmi-tv-score {
  font-family: 'JetBrains Mono', monospace;
  font-size: 11px;
  padding: 2px 6px;
  border-radius: 4px;
  font-weight: 700;
}

.rmi-tv-blip {
  position: fixed;
  top: 140px;
  right: 20px;
  z-index: 99998;
  width: 220px;
  background: linear-gradient(135deg, #1a1a2e, #16213e);
  border: 1px solid #00d4ff;
  border-radius: 12px;
  padding: 14px;
  box-shadow: 0 10px 40px rgba(0, 0, 0, 0.5);
  animation: rmi-blip-in 0.3s ease-out;
}

.rmi-tv-blip-fade {
  animation: rmi-blip-out 0.5s ease-out forwards;
}

.rmi-tv-blip-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 10px;
}

.rmi-tv-blip-symbol {
  font-size: 16px;
  font-weight: 700;
  color: #fff;
}

.rmi-tv-blip-score {
  font-size: 12px;
  padding: 3px 8px;
  border-radius: 4px;
  font-weight: 700;
}

.rmi-tv-blip-body {
  display: flex;
  flex-direction: column;
  gap: 6px;
  margin-bottom: 12px;
}

.rmi-tv-metric {
  display: flex;
  justify-content: space-between;
  font-size: 12px;
}

.rmi-tv-metric span:first-child {
  color: #94a3b8;
}

.rmi-tv-metric span:last-child {
  color: #fff;
  font-weight: 600;
}

.rmi-tv-blip-footer {
  display: flex;
  gap: 8px;
}

.rmi-tv-blip-btn {
  flex: 1;
  padding: 8px;
  border: none;
  border-radius: 6px;
  font-size: 11px;
  font-weight: 600;
  cursor: pointer;
  background: rgba(255, 255, 255, 0.1);
  color: #fff;
  transition: all 0.2s;
}

.rmi-tv-blip-btn:hover {
  background: rgba(255, 255, 255, 0.2);
}

.rmi-tv-blip-btn-upgrade {
  background: linear-gradient(90deg, #00d4ff, #0099cc);
  color: #000;
}

.rmi-tv-panel {
  position: fixed;
  top: 100px;
  right: 20px;
  width: 300px;
  max-height: 70vh;
  background: linear-gradient(135deg, #1a1a2e, #16213e);
  border: 1px solid #00d4ff;
  border-radius: 16px;
  z-index: 99999;
  overflow: hidden;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.5);
  animation: rmi-blip-in 0.3s ease-out;
}

.rmi-tv-panel-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.rmi-tv-panel-header h3 {
  margin: 0;
  font-size: 16px;
  color: #fff;
}

.rmi-tv-panel-close {
  background: none;
  border: none;
  color: #94a3b8;
  font-size: 20px;
  cursor: pointer;
}

.rmi-tv-panel-body {
  padding: 16px;
  overflow-y: auto;
  max-height: calc(70vh - 120px);
}

.rmi-tv-score-large {
  font-size: 48px;
  font-weight: 800;
  text-align: center;
  margin-bottom: 4px;
}

.rmi-tv-score-large span {
  font-size: 18px;
  font-weight: 400;
  opacity: 0.7;
}

.rmi-tv-sections {
  display: flex;
  flex-direction: column;
  gap: 16px;
  margin-top: 20px;
}

.rmi-tv-section h4 {
  font-size: 12px;
  color: #94a3b8;
  margin: 0 0 10px 0;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.rmi-tv-stats {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 12px;
}

.rmi-tv-stats div {
  display: flex;
  flex-direction: column;
  gap: 2px;
}

.rmi-tv-stats span {
  font-size: 11px;
  color: #64748b;
}

.rmi-tv-stats strong {
  font-size: 14px;
  color: #fff;
}

.rmi-tv-section-locked {
  background: rgba(255, 255, 255, 0.03);
  border: 1px dashed rgba(255, 255, 255, 0.2);
  border-radius: 10px;
  padding: 14px;
  text-align: center;
}

.rmi-tv-section-locked p {
  font-size: 12px;
  color: #64748b;
  margin: 0 0 12px 0;
}

.rmi-tv-btn-upgrade {
  background: linear-gradient(90deg, #00d4ff, #0099cc);
  color: #000;
  border: none;
  padding: 10px 20px;
  border-radius: 8px;
  font-size: 13px;
  font-weight: 600;
  cursor: pointer;
}

.rmi-tv-panel-footer {
  padding: 12px 16px;
  border-top: 1px solid rgba(255, 255, 255, 0.1);
  text-align: center;
}

.rmi-tv-link {
  color: #00d4ff;
  text-decoration: none;
  font-size: 13px;
  font-weight: 500;
}

.rmi-tv-modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  background: rgba(0, 0, 0, 0.8);
  z-index: 100000;
  display: flex;
  align-items: center;
  justify-content: center;
}

.rmi-tv-upgrade-modal {
  width: 90%;
  max-width: 360px;
  background: linear-gradient(135deg, #1a1a2e, #16213e);
  border: 1px solid #00d4ff;
  border-radius: 16px;
  padding: 24px;
  text-align: center;
  position: relative;
}

.rmi-tv-upgrade-modal h3 {
  margin: 0 0 16px 0;
  font-size: 20px;
  color: #fff;
}

.rmi-tv-price {
  display: flex;
  align-items: baseline;
  justify-content: center;
  gap: 4px;
  margin-bottom: 20px;
}

.rmi-tv-price-amount {
  font-size: 48px;
  font-weight: 800;
  color: #00d4ff;
}

.rmi-tv-price-period {
  font-size: 18px;
  color: #94a3b8;
}

.rmi-tv-features {
  list-style: none;
  padding: 0;
  margin: 0 0 24px 0;
  text-align: left;
}

.rmi-tv-features li {
  padding: 8px 0;
  color: #e2e8f0;
  font-size: 14px;
  border-bottom: 1px solid rgba(255, 255, 255, 0.05);
}

.rmi-tv-features li:before {
  content: '✓ ';
  color: #22c55e;
  font-weight: 700;
}

.rmi-tv-btn-primary {
  background: linear-gradient(90deg, #00d4ff, #0099cc);
  color: #000;
  border: none;
  padding: 14px 32px;
  border-radius: 10px;
  font-size: 16px;
  font-weight: 600;
  cursor: pointer;
  width: 100%;
}

.rmi-tv-trial {
  font-size: 12px;
  color: #64748b;
  margin-top: 12px;
}

.rmi-tv-modal-close {
  position: absolute;
  top: 12px;
  right: 12px;
  background: none;
  border: none;
  color: #94a3b8;
  font-size: 20px;
  cursor: pointer;
}

/* ===== Scrollbar ===== */
.rmi-modal-body::-webkit-scrollbar,
.rmi-tv-panel-body::-webkit-scrollbar {
  width: 6px;
}

.rmi-modal-body::-webkit-scrollbar-track,
.rmi-tv-panel-body::-webkit-scrollbar-track {
  background: rgba(255, 255, 255, 0.05);
}

.rmi-modal-body::-webkit-scrollbar-thumb,
.rmi-tv-panel-body::-webkit-scrollbar-thumb {
  background: rgba(255, 255, 255, 0.2);
  border-radius: 3px;
}

/* ===== Responsive ===== */
@media (max-width: 640px) {
  #rmi-blip-container {
    left: 10px;
    right: 10px;
    max-width: none;
  }

  .rmi-corner-blip {
    max-width: none;
  }

  .rmi-tv-floating-btn,
  .rmi-tv-blip,
  .rmi-tv-panel {
    right: 10px;
  }

  .rmi-modal {
    width: 95%;
    max-height: 90vh;
  }
}
"}

{"path": "rmi/infrastructure/extension/content_scripts/coingecko.js", "content": "/**
 * RMI CoinGecko Integration
 */

(function() {
  'use strict';

  const RMI_API_BASE = 'https://intel.cryptorugmunch.com/api';
  let currentCoin = null;

  function init() {
    console.log('[RMI] CoinGecko integration loaded');
    startMonitoring();
  }

  function startMonitoring() {
    // Check for coin changes
    setInterval(() => {
      const coin = extractCoin();
      if (coin && (!currentCoin || coin.id !== currentCoin.id)) {
        currentCoin = coin;
        onCoinChange(coin);
      }
    }, 1500);

    // Inject blip on coin pages
    if (location.pathname.includes('/coins/')) {
      injectCoinPageBlip();
    }
  }

  function extractCoin() {
    const urlMatch = location.pathname.match(/\/en\/coins\/([^\/]+)/);
    if (!urlMatch) return null;

    const coinId = urlMatch[1];
    const symbolEl = document.querySelector('.coin-symbol, [data-coin-symbol], .tw-text-gray-500');
    const nameEl = document.querySelector('h1, .coin-name');

    return {
      id: coinId,
      symbol: symbolEl ? symbolEl.textContent.replace(/[()]/g, '').toUpperCase() : coinId.toUpperCase(),
      name: nameEl ? nameEl.textContent.trim() : coinId,
      exchange: 'coingecko'
    };
  }

  async function onCoinChange(coin) {
    const analysis = await fetchAnalysis(coin);
    if (analysis) {
      showCoinGeckoBlip(coin, analysis);
      updateExistingBlips(coin, analysis);
    }
  }

  async function fetchAnalysis(coin) {
    try {
      const { subscription } = await chrome.storage.local.get(['subscription']);
      const tier = subscription?.tier || 'free';

      const response = await fetch(
        `${RMI_API_BASE}/v3/token/symbol/${coin.symbol}?tier=${tier}&source=coingecko`,
        { headers: { 'X-Extension-Version': '3.0.0' } }
      );

      if (!response.ok) return null;
      return await response.json();
    } catch (error) {
      return null;
    }
  }

  function showCoinGeckoBlip(coin, analysis) {
    const existing = document.getElementById('rmi-cg-blip');
    if (existing) existing.remove();

    const blip = document.createElement('div');
    blip.id = 'rmi-cg-blip';
    blip.className = 'rmi-cg-blip';
    blip.innerHTML = `
      <div class="rmi-cg-header">
        <img src="https://assets.coingecko.com/coins/images/1/small/bitcoin.png" class="rmi-cg-icon" alt="">
        <div class="rmi-cg-info">
          <span class="rmi-cg-symbol">${coin.symbol}</span>
          <span class="rmi-cg-name">${coin.name}</span>
        </div>
        <span class="rmi-cg-score rmi-score-${analysis.risk_level}">${analysis.overall_score}</span>
      </div>
      <div class="rmi-cg-body">
        <div class="rmi-cg-metric">
          <span>Risk Level</span>
          <span class="rmi-risk-${analysis.risk_level}">${analysis.risk_level}</span>
        </div>
        ${analysis.price ? `
          <div class="rmi-cg-metric">
            <span>Price</span>
            <span>$${formatPrice(analysis.price)}</span>
          </div>
        ` : ''}
      </div>
      <div class="rmi-cg-footer">
        <button class="rmi-cg-btn" data-action="analyze">Full Analysis</button>
        <button class="rmi-cg-btn rmi-cg-btn-pro" data-action="upgrade">Pro $5/mo</button>
      </div>
    `;

    blip.querySelector('[data-action="analyze"]').addEventListener('click', () => {
      showAnalysisModal(coin, analysis);
    });

    blip.querySelector('[data-action="upgrade"]').addEventListener('click', () => {
      showUpgradeModal();
    });

    document.body.appendChild(blip);
  }

  function injectCoinPageBlip() {
    // Add inline badge to coin header
    const header = document.querySelector('h1') || document.querySelector('.coin-name');
    if (!header || document.getElementById('rmi-cg-inline')) return;

    const badge = document.createElement('span');
    badge.id = 'rmi-cg-inline';
    badge.className = 'rmi-cg-inline-badge';
    badge.innerHTML = '🛡️ Analyze';

    badge.addEventListener('click', () => {
      const coin = extractCoin();
      if (coin) onCoinChange(coin);
    });

    header.parentNode.insertBefore(badge, header.nextSibling);
  }

  function updateExistingBlips(coin, analysis) {
    // Update any existing table badges
    document.querySelectorAll('.rmi-cg-table-badge').forEach(badge => {
      const badgeSymbol = badge.dataset.symbol;
      if (badgeSymbol === coin.symbol) {
        badge.className = `rmi-cg-table-badge rmi-score-${analysis.risk_level}`;
        badge.textContent = analysis.overall_score;
      }
    });
  }

  function showAnalysisModal(coin, analysis) {
    const existing = document.getElementById('rmi-cg-modal');
    if (existing) existing.remove();

    const modal = document.createElement('div');
    modal.id = 'rmi-cg-modal';
    modal.className = 'rmi-cg-modal-overlay';
    modal.innerHTML = `
      <div class="rmi-cg-modal">
        <div class="rmi-cg-modal-header">
          <div class="rmi-cg-modal-title">
            <span class="rmi-cg-modal-symbol">${coin.symbol}</span>
            <span class="rmi-cg-modal-score rmi-score-${analysis.risk_level}">${analysis.overall_score}/100</span>
          </div>
          <button class="rmi-cg-modal-close">&times;</button>
        </div>
        <div class="rmi-cg-modal-body">
          ${generateModalContent(analysis, coin)}
        </div>
        <div class="rmi-cg-modal-footer">
          <a href="https://intel.cryptorugmunch.com/scan/${coin.symbol}" target="_blank" class="rmi-cg-btn rmi-cg-btn-primary">
            Open Dashboard
          </a>
        </div>
      </div>
    `;

    modal.querySelector('.rmi-cg-modal-close').addEventListener('click', () => modal.remove());
    modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });

    document.body.appendChild(modal);
  }

  function generateModalContent(analysis, coin) {
    const flags = analysis.flags?.red || [];
    return `
      <div class="rmi-cg-score-section">
        <div class="rmi-cg-big-score rmi-score-${analysis.risk_level}">${analysis.overall_score}</div>
        <p class="rmi-cg-risk-text">${analysis.risk_level.toUpperCase()} RISK</p>
      </div>

      <div class="rmi-cg-teasers">
        <div class="rmi-cg-teaser">
          <h4>🔒 Market Data</h4>
          <p>Market cap, volume, liquidity ratios</p>
          <button class="rmi-cg-teaser-btn" data-action="upgrade">Unlock Pro</button>
        </div>
        <div class="rmi-cg-teaser">
          <h4>🔒 Risk Breakdown</h4>
          <p>Contract analysis, ownership, security</p>
          <button class="rmi-cg-teaser-btn" data-action="upgrade">Unlock Pro</button>
        </div>
      </div>

      ${flags.length > 0 ? `
        <div class="rmi-cg-alert">
          <p>🚩 ${flags.length} red flags detected</p>
          <button class="rmi-cg-alert-btn" data-action="upgrade">See Details in Pro</button>
        </div>
      ` : ''}

      <div class="rmi-cg-upsell">
        <p>Get complete analysis on CoinGecko and every chart</p>
        <p class="rmi-cg-price"><strong>$5/month</strong> • Cancel anytime</p>
      </div>
    `;
  }

  function showUpgradeModal() {
    const modal = document.createElement('div');
    modal.className = 'rmi-cg-modal-overlay';
    modal.innerHTML = `
      <div class="rmi-cg-modal rmi-cg-upgrade">
        <h3>Upgrade to RMI Pro</h3>
        <div class="rmi-cg-upgrade-price">
          <span>$5</span><small>/month</small>
        </div>
        <ul class="rmi-cg-upgrade-features">
          <li>✓ Full analysis on CoinGecko</li>
          <li>✓ Works on TradingView, CMC & more</li>
          <li>✓ Real-time risk alerts</li>
          <li>✓ Telegram bot access</li>
        </ul>
        <button class="rmi-cg-btn rmi-cg-btn-primary" data-action="subscribe">Start Free Trial</button>
        <p class="rmi-cg-trial">7 days free</p>
        <button class="rmi-cg-modal-close">&times;</button>
      </div>
    `;

    modal.querySelector('[data-action="subscribe"]').addEventListener('click', () => {
      chrome.tabs.create({ url: 'https://intel.cryptorugmunch.com/checkout?plan=pro-extension&source=coingecko' });
      modal.remove();
    });

    modal.querySelector('.rmi-cg-modal-close').addEventListener('click', () => modal.remove());
    modal.addEventListener('click', (e) => { if (e.target === modal) modal.remove(); });

    document.body.appendChild(modal);
  }

  function formatPrice(price) {
    if (price < 0.000001) return price.toExponential(2);
    if (price < 0.01) return price.toFixed(6);
    if (price < 1) return price.toFixed(4);
    return price.toFixed(2);
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', init);
  } else {
    init();
  }
})();
"}

