* {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

body {
  font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
  background: #0f172a;
  color: #e2e8f0;
  min-width: 380px;
  max-width: 380px;
}

.rmi-popup {
  display: flex;
  flex-direction: column;
}

/* ===== Header ===== */
.rmi-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding: 16px;
  background: linear-gradient(135deg, #1e293b 0%, #0f172a 100%);
  border-bottom: 1px solid #334155;
}

.rmi-logo {
  display: flex;
  align-items: center;
  gap: 12px;
}

.rmi-logo-icon {
  font-size: 28px;
}

.rmi-logo-text {
  display: flex;
  flex-direction: column;
}

.rmi-logo-title {
  font-size: 18px;
  font-weight: 700;
  color: #00d4ff;
  line-height: 1.2;
}

.rmi-logo-subtitle {
  font-size: 11px;
  color: #94a3b8;
}

.rmi-tier-badge {
  padding: 4px 12px;
  background: #334155;
  border-radius: 20px;
  font-size: 11px;
  font-weight: 600;
  color: #94a3b8;
  text-transform: uppercase;
}

.rmi-tier-badge.rmi-tier-pro {
  background: linear-gradient(90deg, #00d4ff, #0099cc);
  color: #000;
}

/* ===== Sections ===== */
.rmi-section {
  padding: 16px;
  border-bottom: 1px solid #1e293b;
}

.rmi-section:last-of-type {
  border-bottom: none;
}

.rmi-section h3 {
  font-size: 12px;
