  color: #64748b;
  margin-bottom: 12px;
}

.rmi-pro-renews span {
  color: #94a3b8;
}

/* ===== Quick Scan ===== */
.rmi-scan-input-group {
  display: flex;
  gap: 8px;
}

.rmi-input {
  flex: 1;
  padding: 10px 12px;
  background: #1e293b;
  border: 1px solid #334155;
  border-radius: 8px;
  color: #e2e8f0;
  font-size: 13px;
