{"path": "rmi/infrastructure/extension/popup/popup.js", "content": "/**
 * RMI Extension - Popup Script v3.0
 * Subscription management and pricing tiers
 */

const RMI_API_BASE = 'https://intel.cryptorugmunch.com/api';

// DOM Elements
const elements = {
  // Subscription
  tierBadge: document.getElementById('rmi-tier-badge'),
  subFree: document.getElementById('rmi-sub-free'),
  subPro: document.getElementById('rmi-sub-pro'),
  btnUpgrade: document.getElementById('rmi-btn-upgrade'),
  btnManage: document.getElementById('rmi-btn-manage'),
  renewalDate: document.getElementById('rmi-renewal-date'),

  // Scan
  scanInput: document.getElementById('rmi-scan-input'),
  scanBtn: document.getElementById('rmi-scan-btn'),
  scanResult: document.getElementById('rmi-scan-result'),

  // Site status
  siteName: document.getElementById('rmi-site-name'),
  siteSupport: document.getElementById('rmi-site-support'),
  siteFeatures: document.getElementById('rmi-site-features'),

  // Recent
  recentList: document.getElementById('rmi-recent-list'),
  clearRecent: document.getElementById('rmi-clear-recent'),

  // Upgrade modal
  upgradeModal: document.getElementById('rmi-upgrade-modal'),
  btnSubscribe: document.getElementById('rmi-popup-subscribe'),
  pricingToggle: document.querySelectorAll('.rmi-toggle-btn'),
  proPrice: document.getElementById('rmi-pro-price'),
  proPeriod: document.getElementById('rmi-pro-period'),

  // Settings modal
  settingsModal: document.getElementById('rmi-settings-modal'),
  settingsBtn: document.getElementById('rmi-settings-btn'),
  btnClearCache: document.getElementById('rmi-clear-cache')
};

// State
let subscription = { tier: 'free' };
let currentPlan = 'monthly';

// Initialize
document.addEventListener('DOMContentLoaded', async () => {
  await loadSubscription();
  await detectCurrentSite();
  await loadRecentScans();
  setupEventListeners();
});

// Load subscription status
async function loadSubscription() {
  const data = await chrome.storage.local.get(['subscription']);
  subscription = data.subscription || { tier: 'free' };
  updateSubscriptionUI();
}

// Update subscription UI
function updateSubscriptionUI() {
  if (subscription.tier === 'pro') {
    elements.tierBadge.textContent = 'Pro';
    elements.tierBadge.classList.add('rmi-tier-pro');
    elements.subFree.classList.add('hidden');
    elements.subPro.classList.remove('hidden');

    if (subscription.renews_at) {
      const date = new Date(subscription.renews_at);
      elements.renewalDate.textContent = date.toLocaleDateString();
    }
  } else {
    elements.tierBadge.textContent = 'Free';
    elements.tierBadge.classList.remove('rmi-tier-pro');
    elements.subFree.classList.remove('hidden');
    elements.subPro.classList.add('hidden');
  }
}

// Detect current site
async function detectCurrentSite() {
  try {
    const [tab] = await chrome.tabs.query({ active: true, currentWindow: true });
    if (!tab) return;

    const url = new URL(tab.url);
    const hostname = url.hostname.replace('www.', '');

    const siteNames = {
      'tradingview.com': 'TradingView',
      'coingecko.com': 'CoinGecko',
      'coinmarketcap.com': 'CoinMarketCap',
      'dexscreener.com': 'DexScreener',
      'dextools.io': 'DexTools',
      'birdeye.so': 'Birdeye'
    };

    const siteName = siteNames[hostname] || hostname;
    elements.siteName.textContent = siteName;

    // Check if supported
    const supported = Object.keys(siteNames).some(site => hostname.includes(site));
    if (supported) {
      elements.siteSupport.textContent = 'Full support';
      elements.siteSupport.style.color = '#22c55e';

      // Highlight active site tag
      document.querySelectorAll('.rmi-site-tag').forEach(tag => {
        const site = tag.dataset.site;
        if (hostname.includes(site)) {
          tag.classList.add('active');
        }
      });
    } else {
      elements.siteSupport.textContent = 'Universal detector active';
    }

    // Extract token from URL if present
    const tokenMatch = tab.url.match(/\/(coins|currencies)\/([^\/]+)/);
    if (tokenMatch) {
      elements.scanInput.value = tokenMatch[2].toUpperCase();
    }

  } catch (error) {
    console.error('Error detecting site:', error);
  }
}

// Setup event listeners
function setupEventListeners() {
  // Quick scan
  elements.scanBtn.addEventListener('click', handleQuickScan);
  elements.scanInput.addEventListener('keypress', (e) => {
    if (e.key === 'Enter') handleQuickScan();
  });

  // Clear recent
  elements.clearRecent.addEventListener('click', async () => {
    await chrome.storage.local.set({ recentScans: [] });
    await loadRecentScans();
  });

  // Upgrade
  elements.btnUpgrade.addEventListener('click', () => {
    openModal(elements.upgradeModal);
  });

  // Manage subscription
  elements.btnManage.addEventListener('click', () => {
    chrome.tabs.create({ url: 'https://intel.cryptorugmunch.com/billing' });
  });

  // Subscribe button in modal
  elements.btnSubscribe.addEventListener('click', handleSubscribe);

  // Pricing toggle
  elements.pricingToggle.forEach(btn => {
    btn.addEventListener('click', () => {
      elements.pricingToggle.forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      currentPlan = btn.dataset.plan;
      updatePricingDisplay();
    });
  });

  // Settings
  elements.settingsBtn.addEventListener('click', () => {
    openModal(elements.settingsModal);
  });

  // Close modals
  document.querySelectorAll('.rmi-popup-modal-close').forEach(btn => {
    btn.addEventListener('click', (e) => {
      const modal = e.target.closest('.rmi-popup-modal');
      closeModal(modal);
    });
  });

  // Clear cache
  elements.btnClearCache?.addEventListener('click', async () => {
    await chrome.storage.local.remove(['recentScans', 'tokenCache']);
    alert('Cache cleared!');
  });

  // Site tags click
  document.querySelectorAll('.rmi-site-tag').forEach(tag => {
    tag.addEventListener('click', () => {
      const site = tag.dataset.site;
      const urls = {
        tradingview: 'https://tradingview.com',
        coingecko: 'https://coingecko.com',
        coinmarketcap: 'https://coinmarketcap.com',
        dexscreener: 'https://dexscreener.com',
        dextools: 'https://dextools.io',
        birdeye: 'https://birdeye.so'
      };
      chrome.tabs.create({ url: urls[site] });
    });
  });
}

// Update pricing display
function updatePricingDisplay() {
  if (currentPlan === 'yearly') {
    elements.proPrice.textContent = '$48';
    elements.proPeriod.textContent = '/year';
  } else {
    elements.proPrice.textContent = '$5';
    elements.proPeriod.textContent = '/month';
  }
}

// Handle subscription
function handleSubscribe() {
  const plan = currentPlan === 'yearly' ? 'pro-yearly' : 'pro-monthly';
  chrome.tabs.create({
    url: `https://intel.cryptorugmunch.com/checkout?plan=${plan}&source=extension-popup`
  });
  closeModal(elements.upgradeModal);
}

// Handle quick scan
async function handleQuickScan() {
  const query = elements.scanInput.value.trim();
  if (!query) return;

  elements.scanResult.innerHTML = '<div class="rmi-loading"><div class="rmi-spinner"></div></div>';
  elements.scanResult.classList.remove('hidden');

  try {
    const response = await fetch(`${RMI_API_BASE}/v3/token/symbol/${query}?tier=${subscription.tier}`);
    if (!response.ok) throw new Error('API error');

    const data = await response.json();
    displayScanResult(data);
    await addToRecentScans(data);

  } catch (error) {
    elements.scanResult.innerHTML = `
      <div style="color: #ef4444; text-align: center; padding: 10px;">
        Unable to scan. Try a different symbol.
      </div>
    `;
  }
}

// Display scan result
function displayScanResult(data) {
  const riskLevel = data.risk_level || 'unknown';
  const score = data.overall_score || 0;
  const redFlags = data.flags?.red || [];

  elements.scanResult.className = `rmi-scan-result rmi-risk-${riskLevel}`;
  elements.scanResult.innerHTML = `
    <div class="rmi-result-header">
      <span class="rmi-result-symbol">${data.symbol || data.token_symbol || 'Unknown'}</span>
      <span class="rmi-result-score rmi-score-${riskLevel}">${score}/100</span>
    </div>
    <div class="rmi-result-flags">
      ${redFlags.length > 0 ? `🚩 ${redFlags.length} red flags` : 'No major red flags'}
    </div>
    <div class="rmi-result-actions">
      <a href="https://intel.cryptorugmunch.com/scan/${data.token_address || data.symbol}" 
         target="_blank" class="rmi-btn rmi-btn-primary">
        Full Analysis
      </a>
      ${subscription.tier === 'free' ? `
        <button class="rmi-btn rmi-btn-upgrade" onclick="document.getElementById('rmi-btn-upgrade').click()">
          Unlock Pro
        </button>
      ` : ''}
    </div>
  `;
}

// Add to recent scans
async function addToRecentScans(data) {
  const stored = await chrome.storage.local.get(['recentScans']);
  const scans = stored.recentScans || [];

  scans.unshift({
    symbol: data.symbol || data.token_symbol,
    address: data.token_address,
    score: data.overall_score,
    riskLevel: data.risk_level,
    timestamp: Date.now()
  });

  const trimmed = scans.slice(0, 20);
  await chrome.storage.local.set({ recentScans: trimmed });
  await loadRecentScans();
}

// Load recent scans
async function loadRecentScans() {
  const data = await chrome.storage.local.get(['recentScans']);
  const scans = data.recentScans || [];

  if (scans.length === 0) {
    elements.recentList.innerHTML = '<div class="rmi-empty">No recent scans</div>';
    return;
  }

  elements.recentList.innerHTML = scans.slice(0, 5).map(scan => `
    <div class="rmi-recent-item" data-symbol="${scan.symbol || ''}">
      <div class="rmi-recent-info">
        <span class="rmi-recent-symbol">${scan.symbol || 'Unknown'}</span>
        <span class="rmi-recent-time">${formatTime(scan.timestamp)}</span>
      </div>
      <span class="rmi-recent-score rmi-score-${scan.riskLevel}">${scan.score}/100</span>
    </div>
  `).join('');

  // Add click handlers
  elements.recentList.querySelectorAll('.rmi-recent-item').forEach(item => {
    item.addEventListener('click', () => {
      const symbol = item.dataset.symbol;
      if (symbol) {
        chrome.tabs.create({ url: `https://intel.cryptorugmunch.com/scan/${symbol}` });
      }
    });
  });
}

// Modal helpers
function openModal(modal) {
  modal.classList.remove('hidden');
}

function closeModal(modal) {
  modal.classList.add('hidden');
}

// Format time
function formatTime(timestamp) {
  const diff = Date.now() - timestamp;
  if (diff < 60000) return 'Just now';
  if (diff < 3600000) return `${Math.floor(diff / 60000)}m ago`;
  if (diff < 86400000) return `${Math.floor(diff / 3600000)}h ago`;
  return `${Math.floor(diff / 86400000)}d ago`;
}
"}

