// Initialize on install
chrome.runtime.onInstalled.addListener((details) => {
  console.log('[RMI] Extension installed:', details.reason);

  // Set default settings
  chrome.storage.local.set({
    subscription: { tier: 'free' },
    settings: {
      showBlips: true,
      sounds: false,
      cacheData: true
    },
    recentScans: [],
    scanCount: 0,
    installDate: new Date().toISOString()
  });

  // Schedule periodic tasks
  chrome.alarms.create('syncSubscription', { periodInMinutes: 60 });
  chrome.alarms.create('cleanupCache', { periodInMinutes: 120 });

  // Show welcome notification
  if (details.reason === 'install') {
    chrome.notifications.create({
      type: 'basic',
      iconUrl: 'icons/icon128.png',
      title: 'RMI Chart Intel Installed',
      message: 'Click the icon to upgrade to Pro for $5/month!'
    });
  }
});

// Handle alarms
chrome.alarms.onAlarm.addListener(async (alarm) => {
  switch (alarm.name) {
    case 'syncSubscription':
      await syncSubscription();
      break;
    case 'cleanupCache':
      await cleanupCache();
      break;
  }
});

// Handle messages from content scripts and popup
chrome.runtime.onMessage.addListener((message, sender, sendResponse) => {
  (async () => {
    try {
      switch (message.action) {
        case 'scanToken':
          const result = await scanToken(message.address, message.tier);
          sendResponse({ success: true, data: result });
          break;

        case 'getTokenData':
          const data = await getTokenData(message.address, message.tier);
          sendResponse({ success: true, data });
          break;

        case 'validateSubscription':
          const sub = await validateSubscription();
          sendResponse({ success: true, subscription: sub });
          break;

        case 'getSubscription':
          const currentSub = await getSubscription();
          sendResponse({ success: true, subscription: currentSub });
          break;

        case 'trackScan':
          await trackScan(message.token);
          sendResponse({ success: true });
          break;

        case 'trackUpgradeClick':
          await trackEvent('upgrade_click', message.source);
          sendResponse({ success: true });
          break;

        default:
          sendResponse({ success: false, error: 'Unknown action' });
      }
    } catch (error) {
      console.error('[RMI] Message handler error:', error);
      sendResponse({ success: false, error: error.message });
    }
  })();

  return true;
});

// Scan token via API
async function scanToken(address, tier = 'free') {
  try {
    const response = await fetch(`${RMI_API_BASE}/v3/token/${address}?tier=${tier}`, {
      headers: {
        'X-Extension-Version': chrome.runtime.getManifest().version,
        'X-Tier': tier
      }
    });

    if (!response.ok) {
      throw new Error(`HTTP ${response.status}`);
    }

    const data = await response.json();

    // Cache result
    data.cached_at = Date.now();
    await chrome.storage.local.set({ [`token_${address}`]: data });

    // Update stats
    const stats = await chrome.storage.local.get(['scanCount']);
    await chrome.storage.local.set({ scanCount: (stats.scanCount || 0) + 1 });

    return data;
  } catch (error) {
    console.error('[RMI] Scan error:', error);
    throw error;
  }
}

// Get cached token data
async function getTokenData(address, tier = 'free') {
  const cached = await chrome.storage.local.get(`token_${address}`);

  if (cached[`token_${address}`]) {
    const data = cached[`token_${address}`];

    // Check if cache is still valid (5 minutes)
    if (Date.now() - data.cached_at < 5 * 60 * 1000) {
      return data;
    }
  }

  // Fetch fresh data
  return await scanToken(address, tier);
}

// Validate subscription with server
async function validateSubscription() {
  try {
    // Get stored subscription
    const stored = await chrome.storage.local.get(['subscription']);
    const subscription = stored.subscription || { tier: 'free' };

    // If pro, validate with server
    if (subscription.tier === 'pro' && subscription.token) {
      const response = await fetch(`${RMI_API_BASE}/v3/validate-subscription`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ token: subscription.token })
      });

      if (response.ok) {
        const data = await response.json();

        // Update stored subscription
        const updatedSub = {
          ...subscription,
          valid: data.valid,
          expires_at: data.expires_at,
          renews_at: data.renews_at
        };

        await chrome.storage.local.set({ subscription: updatedSub });
        return updatedSub;
      }
    }

    return subscription;
  } catch (error) {
    console.error('[RMI] Subscription validation error:', error);
    return { tier: 'free' };
  }
}

// Get current subscription
async function getSubscription() {
  const data = await chrome.storage.local.get(['subscription']);
  return data.subscription || { tier: 'free' };
}

// Sync subscription status
async function syncSubscription() {
  const sub = await validateSubscription();

  // Notify content scripts if subscription changed
  if (sub.tier === 'pro') {
    const tabs = await chrome.tabs.query({});
    for (const tab of tabs) {
      try {
        await chrome.tabs.sendMessage(tab.id, { 
          action: 'subscriptionUpdated', 
          subscription: sub 
        });
      } catch (e) {
        // Tab may not have content script
      }
    }
  }

  return sub;
}

// Track scan for analytics
async function trackScan(token) {
  try {
    await fetch(`${RMI_API_BASE}/v3/track-scan`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        token: token,
        source: 'extension',
        timestamp: new Date().toISOString()
      })
    });
  } catch (error) {
    // Silent fail for analytics
  }
}

// Track event for analytics
async function trackEvent(event, source) {
  try {
    await fetch(`${RMI_API_BASE}/v3/track-event`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        event,
        source,
        timestamp: new Date().toISOString()
      })
    });
  } catch (error) {
    // Silent fail
  }
}

// Cleanup old cache
async function cleanupCache() {
  const allData = await chrome.storage.local.get(null);
  const now = Date.now();
  const ONE_DAY = 24 * 60 * 60 * 1000;

  for (const [key, value] of Object.entries(allData)) {
    // Clean up old token cache
    if (key.startsWith('token_') && value.cached_at) {
      if (now - value.cached_at > ONE_DAY) {
        await chrome.storage.local.remove(key);
      }
    }

    // Clean up old analysis cache
    if (key.startsWith('analysis_') && value.cached_at) {
      if (now - value.cached_at > ONE_DAY) {
        await chrome.storage.local.remove(key);
      }
    }
  }

  console.log('[RMI] Cache cleanup completed');
}

// Handle tab updates for supported sites
chrome.tabs.onUpdated.addListener(async (tabId, changeInfo, tab) => {
  if (changeInfo.status === 'complete' && tab.url) {
    const supportedSites = [
      'tradingview.com',
      'coingecko.com', 
      'coinmarketcap.com',
      'dexscreener.com',
      'dextools.io',
      'birdeye.so'
    ];

    const isSupported = supportedSites.some(site => tab.url.includes(site));

    if (isSupported) {
      // Inject consent banner if needed
      const { rmi_consent } = await chrome.storage.local.get(['rmi_consent']);
      if (!rmi_consent) {
        chrome.scripting.executeScript({
          target: { tabId },
          func: showConsentBanner
        });
      }
    }
  }
});

// Show consent banner function
function showConsentBanner() {
  if (document.getElementById('rmi-consent-banner')) return;

  const banner = document.createElement('div');
  banner.id = 'rmi-consent-banner';
  banner.innerHTML = `
    <div class="rmi-consent-content">
      <div class="rmi-consent-icon">🛡️</div>
      <div class="rmi-consent-text">
        <strong>RMI Chart Intel</strong>
        <p>Enable token analysis on this site? We scan for risk scores and fundamentals.</p>
      </div>
      <div class="rmi-consent-buttons">
        <button id="rmi-consent-yes" class="rmi-btn rmi-btn-primary">Enable</button>
        <button id="rmi-consent-no" class="rmi-btn rmi-btn-secondary">Not Now</button>
      </div>
    </div>
  `;

  const style = document.createElement('style');
  style.textContent = `
    #rmi-consent-banner {
      position: fixed;
      bottom: 20px;
      right: 20px;
      width: 380px;
      max-width: calc(100vw - 40px);
      background: linear-gradient(135deg, #1a1a2e 0%, #16213e 100%);
      border: 1px solid #00d4ff;
      border-radius: 12px;
      padding: 20px;
      z-index: 999999;
      box-shadow: 0 10px 40px rgba(0, 212, 255, 0.3);
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      animation: rmi-slide-in 0.3s ease-out;
    }
    @keyframes rmi-slide-in {
      from { transform: translateX(100%); opacity: 0; }
      to { transform: translateX(0); opacity: 1; }
    }
    .rmi-consent-content {
      display: flex;
      flex-direction: column;
      gap: 15px;
    }
    .rmi-consent-icon { font-size: 32px; text-align: center; }
    .rmi-consent-text { color: #fff; }
    .rmi-consent-text strong { display: block; font-size: 16px; margin-bottom: 8px; color: #00d4ff; }
    .rmi-consent-text p { margin: 0; font-size: 13px; line-height: 1.5; color: #aaa; }
    .rmi-consent-buttons { display: flex; gap: 10px; }
    .rmi-btn {
      flex: 1;
      padding: 10px 16px;
      border: none;
      border-radius: 8px;
      font-size: 13px;
      font-weight: 600;
      cursor: pointer;
      transition: all 0.2s;
    }
    .rmi-btn-primary {
      background: linear-gradient(90deg, #00d4ff, #0099cc);
      color: #000;
    }
    .rmi-btn-primary:hover {
      transform: translateY(-2px);
      box-shadow: 0 4px 12px rgba(0, 212, 255, 0.4);
    }
    .rmi-btn-secondary {
      background: #333;
      color: #aaa;
    }
    .rmi-btn-secondary:hover {
      background: #444;
      color: #fff;
    }
  `;

  document.head.appendChild(style);
  document.body.appendChild(banner);

  document.getElementById('rmi-consent-yes').addEventListener('click', async () => {
    await chrome.storage.local.set({ rmi_consent: true, rmi_consent_date: new Date().toISOString() });
    banner.remove();
  });

  document.getElementById('rmi-consent-no').addEventListener('click', () => {
    banner.remove();
  });
}
"}
